}

# Plot 1: PPV by mechanism and λ
p1 <- ggplot(all_results, aes(x = mechanism, y = ppv, fill = factor(lambda))) +
  geom_violin(position = position_dodge(width = 0.9), alpha = 0.6) +
  geom_boxplot(position = position_dodge(width = 0.9), width = 0.2, alpha = 0.8) +
  geom_hline(yintercept = 0.8, linetype = "dashed", color = "red") +
  scale_y_continuous(labels = scales::percent) +
  scale_fill_brewer(palette = "Set2", name = "λ") +
  labs(
    title = "Positive Predictive Value by Q-Generation Mechanism",
    subtitle = sprintf("If reject H0^S at α=%.2f, what fraction reject H0^Y?", ALPHA),
    x = "Q-Generation Mechanism",
    y = "PPV = P(reject H0^Y | reject H0^S)",
    caption = "Red line: 80% PPV threshold"
  ) +
  theme_minimal() +
  theme(axis.text.x = element_text(angle = 45, hjust = 1))

ggsave("sims/results/decision_ppv_by_mechanism.png", p1,
       width = 10, height = 6, dpi = 300)
cat("  Saved: sims/results/decision_ppv_by_mechanism.png\n")

# Plot 2: φ̂ vs empirical PPV
p2 <- ggplot(all_results, aes(x = phi_estimate, y = ppv, color = mechanism)) +
  geom_point(alpha = 0.5, size = 2) +
  geom_smooth(method = "lm", se = TRUE, alpha = 0.2) +
  geom_abline(intercept = 0, slope = 1, linetype = "dashed", color = "gray50") +
  scale_x_continuous(limits = c(0, 1)) +
  scale_y_continuous(limits = c(0, 1), labels = scales::percent) +
  facet_wrap(~lambda, labeller = label_both) +
  labs(
    title = "Relationship: Estimated φ̂(F_λ) vs. Empirical PPV",
    subtitle = "Does high correlation predict reliable decisions?",
    x = "Estimated correlation φ̂(F_λ)",
    y = "Empirical PPV",
    color = "Q mechanism",
    caption = "Dashed line: perfect calibration (PPV = φ̂)"
  ) +
  theme_minimal() +
  theme(legend.position = "bottom")

ggsave("sims/results/decision_phi_vs_ppv.png", p2,
       width = 12, height = 8, dpi = 300)
cat("  Saved: sims/results/decision_phi_vs_ppv.png\n")

# Plot 3: Decision outcomes (2x2 contingency)
decision_counts <- all_results %>%
  group_by(mechanism, lambda) %>%
  summarise(
    both_reject = mean(n_both_reject / N_TEST_STUDIES),
    S_only = mean((n_reject_S - n_both_reject) / N_TEST_STUDIES),
    Y_only = mean((n_reject_Y - n_both_reject) / N_TEST_STUDIES),
    both_null = mean(n_both_null / N_TEST_STUDIES),
    .groups = "drop"
  ) %>%
  tidyr::pivot_longer(
    cols = c(both_reject, S_only, Y_only, both_null),
    names_to = "outcome",
    values_to = "proportion"
  ) %>%
  mutate(
    outcome = factor(outcome,
                     levels = c("both_reject", "S_only", "Y_only", "both_null"),
                     labels = c("Both reject\n(True positive)",
                                "S only\n(False positive)",
                                "Y only\n(False negative)",
                                "Both null\n(True negative)"))
  )

p3 <- ggplot(decision_counts, aes(x = mechanism, y = proportion, fill = outcome)) +
  geom_col(position = "stack") +
  scale_y_continuous(labels = scales::percent) +
  scale_fill_brewer(palette = "RdYlGn", name = "Decision outcome") +
  facet_wrap(~lambda, labeller = label_both) +
  labs(
    title = "Decision Outcome Distribution",
    subtitle = "Hypothesis test results: reject/fail to reject for S and Y",
    x = "Q-Generation Mechanism",
    y = "Proportion of test studies"
  ) +
  theme_minimal() +
  theme(axis.text.x = element_text(angle = 45, hjust = 1),
        legend.position = "bottom")

ggsave("sims/results/decision_outcomes.png", p3,
       width = 12, height = 8, dpi = 300)
cat("  Saved: sims/results/decision_outcomes.png\n")

# Save detailed results
saveRDS(all_results, "sims/results/decision_validation_detailed.rds")
cat("\n  Saved: sims/results/decision_validation_detailed.rds\n")

cat("\n")
cat("================================================================\n")
cat("PAPER IMPLICATIONS\n")
cat("================================================================\n\n")

if (overall_ppv >= 0.8) {
  cat("Key Finding:\n")
  cat(sprintf("  When the surrogate test is significant (α=%.2f), the outcome\n", ALPHA))
  cat(sprintf("  test is also significant in %.0f%% of cases (PPV). This holds\n",
              overall_ppv * 100))
  cat("  across multiple Q-generation mechanisms, including covariate\n")
  cat("  shift and selection bias (not just our mixture model).\n\n")

  cat("Paper Claim:\n")
  cat("  'Decision validation demonstrates that regulatory decisions based\n")
  cat("   on the surrogate are highly reliable: when ΔS is statistically\n")
  cat(sprintf("   significant at the %.0f%% level, ΔY is also significant in\n",
              (1 - ALPHA) * 100))
  cat(sprintf("   %.0f%% of future studies. This high positive predictive value\n",
              overall_ppv * 100))
  cat("   holds across diverse distribution shifts, confirming that the\n")
  cat("   surrogate provides valid guidance for regulatory decisions.'\n")
} else if (overall_ppv >= 0.6) {
  cat("Finding:\n")
  cat(sprintf("  PPV of %.0f%% indicates moderate reliability.\n", overall_ppv * 100))
  cat("  Surrogate provides useful but imperfect guidance.\n\n")

  cat("Recommendations:\n")
  cat("  - Use surrogate for early-stage decisions (Phase II)\n")
  cat("  - Confirm with outcome in pivotal trials (Phase III)\n")
  cat("  - Consider adjustment for multiple comparisons\n")
} else {
  cat("Finding:\n")
  cat("  Low PPV suggests surrogate may not be reliable for decisions.\n\n")

  cat("Possible explanations:\n")
  cat("  - True correlation is low\n")
  cat("  - Sample sizes insufficient for power\n")
  cat("  - Distribution shifts are too large (λ too high)\n")
}

